function cor = checkFixation(td)global constant scr visual params timeout = 1.00; % maximum fixation check timetCorMin = 0.20; % minimum correct fixation time% % % determine recorded eyeif constant.EYETRACK    if ~isfield(constant,'DOMEYE')        evt = Eyelink('newestfloatsample');        constant.DOMEYE = find(evt.gx ~= -32768);    endendcxm = td.fixLoc(1);cym = td.fixLoc(2);rad = visual.fixCheckRad;Eyelink('command','draw_box %d %d %d %d 15', cxm-rad, cym-rad, cxm+rad, cym+rad);% % cuerct = CenterRectOnPoint([0,0,4,4],scr.xres/2, scr.yres/2);% cuetex = Screen('MakeTexture',scr.main,cat(3,ones(4),CreateCircularAperture(4)),[],[],2);% % % fixrct = CenterRectOnPoint([0,0,12,12],scr.xres/2, scr.yres/2);% fixtex = Screen('MakeTexture',scr.main,cat(3,ones(12),CreateCircle(12,1)),[],[],2);% barpos = nan(2,2,2);% barpos(:,:,1) = [scr.xres/2+[-15,+15]/sqrt(2);scr.yres/2+[-15,+15]/sqrt(2)];% barpos(:,:,2) = [scr.xres/2+[-15,+15]/sqrt(2);scr.yres/2+[+15,-15]/sqrt(2)];% % extrabarpos = nan(2,2,2);% extrabarpos(:,:,2) = [scr.xres/2+[-20,0]/sqrt(2);scr.yres/2+[0,-20]/sqrt(2)];% extrabarpos(:,:,1) = [scr.xres/2+[-20,0]/sqrt(2);scr.yres/2+[0,20]/sqrt(2)];% % extrabarpos2 = nan(2,2,2);% extrabarpos2(:,:,2) = [scr.xres/2+[0,20]/sqrt(2);scr.yres/2+[20,0]/sqrt(2)];% extrabarpos2(:,:,1) = [scr.xres/2+[0,20]/sqrt(2);scr.yres/2+[-20,0]/sqrt(2)];barpos             = nan(2,2,2);barpos(:,:,1)      = [scr.xres/2+[-15,+15]; scr.yres/2+[0,0]];barpos(:,:,2)      = [scr.xres/2+[0,0];     scr.yres/2+[-15,+15]];patchrct = [ ...    CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2,scr.yres/2); ... %0        CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2-params.gaborexc(2),scr.yres/2); ... %WEST  4    CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2,scr.yres/2-params.gaborexc(2)); ... %NORTH 4    CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2+params.gaborexc(2),scr.yres/2); ... %EAST  4    CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2,scr.yres/2+params.gaborexc(2)); ... %SOUTH 4        CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2-params.gaborexc(3),scr.yres/2); ... %WEST  8    CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2,scr.yres/2-params.gaborexc(3)); ... %NORTH 8    CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2+params.gaborexc(3),scr.yres/2); ... %EAST  8    CenterRectOnPoint([0,0,params.patchsiz,params.patchsiz],scr.xres/2,scr.yres/2+params.gaborexc(3)); ... %SOUTH 8    ];% placetex = Screen('MakeTexture',scr.main,cat(3,ones(params.gaborsiz),CreateCircle(params.gaborsiz,2)),[],[],1);for iloc=1:params.nLoc    %     Screen('DrawTexture',scr.main,placetex,[],gaborrct(iloc,:),[],[],[],0);    drawPlaceHolders(scr.main,visual.black,patchrct(iloc,:),params.lengthPlaceHolder,params.patchsiz,params.offsetPosPlaceHolder,params.widthPlaceHolder)end% Screen('DrawTexture',scr.main,cuetex,[],cuerct,[],[],[],0);% Screen('DrawTexture',scr.main,fixtex,[],fixrct,[],[],[],0);% drawFixationX(visual.neutral,[cxm cym])drawFixation(visual.neutral,td.fixLoc);Screen('DrawingFinished',scr.main);Screen(scr.main,'Flip');Eyelink('message', 'EVENT_FixationCheck');tstart=GetSecs;cor=0;corStart=0;tCor=0;t=tstart;while ((t-tstart) < timeout && tCor<=tCorMin)    [x,y] = getCoord;        if sqrt((x-cxm)^2+(y-cym)^2)<rad        cor = 1;    else        cor = 0;    end	if cor == 1 && corStart == 0		tCorStart = GetSecs; 		corStart = 1;	elseif cor == 1 && corStart == 1		tCor = GetSecs-tCorStart;	else		corStart = 0;	end		t=GetSecs;end